interface.signature:
interface TrainingSessionState {
  confidenceBefore: number | null;  // 1-5 scale
  confidenceAfter: number | null;   // 1-5 scale
  confidenceChange: number | null;  // Delta (after - before)
}

interface Session {
  id: string;
  timestamp: string;
  module: 'training';
  status: 'completed' | 'in_progress' | 'abandoned';
  drillCount: number;
  accuracy: number;
  confidenceBefore: number;  // 1-5
  confidenceAfter: number;   // 1-5
  confidenceChange: number;  // Delta
  duration: number;          // milliseconds
}

interface ConfidencePromptProps {
  onSelect: (confidence: number) => void;  // 1-5 callback
  isOpen: boolean;
}
